import{_ as a,o as e,c as r,a3 as d}from"./chunks/framework.C49Ar5GK.js";const c=JSON.parse('{"title":"六周学习计划：从零到能改 veRL","description":"每周目标、每日任务、产出物和通关条件明确的 veRL 渐进学习计划","frontmatter":{"title":"六周学习计划：从零到能改 veRL","description":"每周目标、每日任务、产出物和通关条件明确的 veRL 渐进学习计划","lesson":{"stage":"00 · 定位","order":1,"time":"20 分钟规划","level":"路线图","question":"每天学什么、做什么，六周后才能真的具备修改框架的能力？"}},"headers":[],"relativePath":"guide/learning-plan.md","filePath":"guide/learning-plan.md","lastUpdated":null}'),l={name:"guide/learning-plan.md"};function o(n,t,s,i,h,p){return e(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="六周学习计划-从零到能改-verl" tabindex="-1">六周学习计划：从零到能改 veRL <a class="header-anchor" href="#六周学习计划-从零到能改-verl" aria-label="Permalink to &quot;六周学习计划：从零到能改 veRL&quot;">​</a></h1><p>这份计划默认你会 Python、用过 PyTorch 或 Transformers，但没有系统学过强化学习；每周安排 5 天、每天 60–90 分钟，周末留给补课或复盘。目标不是六周“精通所有后端”，而是获得三项可迁移能力：解释算法、跟踪数据、用证据改系统。</p><p>若你已经通过某周的通关检查，可以跳过阅读，但仍建议完成该周产出物。</p><h2 id="全程只维护一份学习档案" tabindex="-1">全程只维护一份学习档案 <a class="header-anchor" href="#全程只维护一份学习档案" aria-label="Permalink to &quot;全程只维护一份学习档案&quot;">​</a></h2><p>新建 <code>learning-log.md</code>，固定六个小节：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 我现在的心智模型</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 字段词典：字段 / shape / 写入者 / 读取者</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 调用链：函数 / 输入 / 输出 / 进程</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 实验账本：假设 / 改动 / 指标 / 结论</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 失败记录：现象 / 最小证据 / 根因 / 修复</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 仍然不会的问题</span></span></code></pre></div><p>这份档案比“读完多少页”更能说明进度。每周只更新同一份，不另开零散笔记。</p><h2 id="第-1-周-把-llm-看成会做动作的策略" tabindex="-1">第 1 周：把 LLM 看成会做动作的策略 <a class="header-anchor" href="#第-1-周-把-llm-看成会做动作的策略" aria-label="Permalink to &quot;第 1 周：把 LLM 看成会做动作的策略&quot;">​</a></h2><p><strong>本周问题：</strong> 文本生成为什么能被强化学习训练？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/fundamentals/llm">LLM 如何成为策略</a>：手算一个三词词表的 softmax 与 log-prob</td><td>写出 prompt、state、token action 的对应关系</td></tr><tr><td>Day 2</td><td><a href="/losh_has_blog/verl-learning/fundamentals/math-toolkit">够用的数学工具</a>：期望、对数、梯度、重要性比率</td><td>完成页面内四道手算题</td></tr><tr><td>Day 3</td><td><a href="/losh_has_blog/verl-learning/fundamentals/rl">强化学习的完整闭环</a>：reward、return、value、advantage</td><td>画一条 4-token 轨迹并标字段</td></tr><tr><td>Day 4</td><td><a href="/losh_has_blog/verl-learning/algorithms/policy-gradient">策略梯度这座桥</a>：解释 (A&gt;0) 与 (A&lt;0)</td><td>用一句人话和一条公式解释更新方向</td></tr><tr><td>Day 5</td><td>复盘：不看网页重画“生成 → 评价 → 更新”</td><td>一页心智模型 v1</td></tr></tbody></table><p><strong>通关条件：</strong> 看到 <code>old_log_probs</code>、<code>response_mask</code>、<code>advantages</code> 时，能说明它们为何存在，而不只是翻译名字。</p><div class="warning custom-block"><p class="custom-block-title">不要在本周做的事</p><p>不用推导 Transformer，也不用证明策略梯度定理。你需要的是足够准确地预测数据流；证明可以作为以后选修。</p></div><h2 id="第-2-周-让-ppo-与-grpo-公式变成张量" tabindex="-1">第 2 周：让 PPO 与 GRPO 公式变成张量 <a class="header-anchor" href="#第-2-周-让-ppo-与-grpo-公式变成张量" aria-label="Permalink to &quot;第 2 周：让 PPO 与 GRPO 公式变成张量&quot;">​</a></h2><p><strong>本周问题：</strong> 为什么不能简单地“奖励高就加大梯度”？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/algorithms/ppo">PPO 与 GAE</a>前半：TD error、GAE、return</td><td>标出 ([B,T]) 中哪些位置被 mask</td></tr><tr><td>Day 2</td><td>PPO clipped objective：手算正负 advantage 下的 clipping</td><td>一张 ratio/clip 决策表</td></tr><tr><td>Day 3</td><td><a href="/losh_has_blog/verl-learning/algorithms/grpo-family">GRPO、Dr.GRPO 与 DAPO</a>：组内基线</td><td>手算同一 prompt 的 4 个 reward</td></tr><tr><td>Day 4</td><td>对照 <code>core_algos.py</code>：公式符号逐一映射到参数</td><td>源码字段词典 v1</td></tr><tr><td>Day 5</td><td>选择 PPO 或 GRPO，口述一遍完整算法</td><td>3 分钟录音或文字讲解</td></tr></tbody></table><p><strong>通关条件：</strong> 能解释 PPO 是更新约束，GAE/GRPO 是优势估计方式；也能解释 DAPO 是一组配方，不是单个 <code>adv_estimator</code>。</p><h2 id="第-3-周-跑通第一个可验证实验" tabindex="-1">第 3 周：跑通第一个可验证实验 <a class="header-anchor" href="#第-3-周-跑通第一个可验证实验" aria-label="Permalink to &quot;第 3 周：跑通第一个可验证实验&quot;">​</a></h2><p><strong>本周问题：</strong> “程序在跑”与“训练语义正确”之间差什么证据？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/practice/first-run">第一次可验证实验</a>：检查环境、数据和版本</td><td>环境清单与固定提交</td></tr><tr><td>Day 2</td><td>只准备/检查 Parquet；打印一条样本和 token 长度</td><td>数据契约表</td></tr><tr><td>Day 3</td><td><a href="/losh_has_blog/verl-learning/practice/configuration">读懂 Hydra 配置</a>：先解析再启动</td><td>保存完整解析配置</td></tr><tr><td>Day 4</td><td>跑到第一个训练 step；保留 rollout 样本和关键指标</td><td>smoke-run 证据包</td></tr><tr><td>Day 5</td><td><a href="/losh_has_blog/verl-learning/practice/reward-function">写一个可靠奖励函数</a>：先单测再接训练</td><td>至少 6 个边界测试</td></tr></tbody></table><p><strong>通关条件：</strong> 换一台机器时，你能说清模型、数据、命令、配置、环境和提交版本，而不是只给一段终端截图。</p><p>没有合适 GPU 也能完成 Day 1–3 和奖励函数测试；不要为了“必须训练”跳过数据与配置理解。</p><h2 id="第-4-周-沿一个-uid-读完-v1-主链" tabindex="-1">第 4 周：沿一个 <code>uid</code> 读完 V1 主链 <a class="header-anchor" href="#第-4-周-沿一个-uid-读完-v1-主链" aria-label="Permalink to &quot;第 4 周：沿一个 \`uid\` 读完 V1 主链&quot;">​</a></h2><p><strong>本周问题：</strong> 一条样本到底存在哪里、由谁补齐字段？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/guide/version-boundary">版本边界</a> + <a href="/losh_has_blog/verl-learning/guide/source-map">源码地图</a></td><td>确认只读 V1，不混入 legacy</td></tr><tr><td>Day 2</td><td><a href="/losh_has_blog/verl-learning/internals/architecture">整体架构</a> + <a href="/losh_has_blog/verl-learning/internals/entry-and-init">入口与初始化</a></td><td>进程/对象/资源三列图</td></tr><tr><td>Day 3</td><td><a href="/losh_has_blog/verl-learning/internals/rollout-to-update">从推理到训练</a>前半</td><td>rollout → reward 时序图</td></tr><tr><td>Day 4</td><td>同页后半：old/ref/value/advantage/update</td><td>字段生命周期 v2</td></tr><tr><td>Day 5</td><td>在源码中从 <code>main_ppo.py</code> 追到 <code>_update_actor()</code></td><td>带文件和函数名的完整调用链</td></tr></tbody></table><p><strong>通关条件：</strong> 能指出 <code>_step_once()</code> 九个阶段；能区分 <code>KVBatchMeta</code> 句柄、TransferQueue 中的值、临时 DataProto 和 worker 读取的 TensorDict。</p><h2 id="第-5-周-理解分布式组织-而不是背-ray-名词" tabindex="-1">第 5 周：理解分布式组织，而不是背 Ray 名词 <a class="header-anchor" href="#第-5-周-理解分布式组织-而不是背-ray-名词" aria-label="Permalink to &quot;第 5 周：理解分布式组织，而不是背 Ray 名词&quot;">​</a></h2><p><strong>本周问题：</strong> 控制器、角色、进程、GPU 和推理后端怎样组合？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/internals/data-structures">数据结构与组织</a>：画出数据所有权</td><td>谁持有 value、谁只持有 key</td></tr><tr><td>Day 2</td><td><a href="/losh_has_blog/verl-learning/internals/workers">Worker 与资源编排</a>：区分 Ray actor 与 veRL role</td><td>资源放置表</td></tr><tr><td>Day 3</td><td>对照配置分析 colocate/separate 的内存与通信</td><td>两种部署的取舍表</td></tr><tr><td>Day 4</td><td><a href="/losh_has_blog/verl-learning/practice/debugging">从现象定位故障</a>：设计三个故障注入</td><td>最小证据清单</td></tr><tr><td>Day 5</td><td>删除/改错一个非关键配置，在测试环境观察首个失败点</td><td>一份因果明确的失败记录</td></tr></tbody></table><p><strong>通关条件：</strong> 遇到卡住、OOM 或 worker died 时，先定位阶段和角色，再调参数；能说出哪种证据会推翻自己的初始猜测。</p><h2 id="第-6-周-做一次最小但完整的框架改造" tabindex="-1">第 6 周：做一次最小但完整的框架改造 <a class="header-anchor" href="#第-6-周-做一次最小但完整的框架改造" aria-label="Permalink to &quot;第 6 周：做一次最小但完整的框架改造&quot;">​</a></h2><p><strong>本周问题：</strong> 怎样改功能或性能，同时保住算法语义和可回退性？</p><table tabindex="0"><thead><tr><th>天</th><th>阅读与任务</th><th>当天产出</th></tr></thead><tbody><tr><td>Day 1</td><td><a href="/losh_has_blog/verl-learning/customization/extension-map">扩展点地图</a>：选最小侵入层</td><td>一页设计：目标/契约/不变量</td></tr><tr><td>Day 2</td><td><a href="/losh_has_blog/verl-learning/customization/custom-algorithm">实现自定义算法</a>或自定义 reward/replay</td><td>单元测试先失败后通过</td></tr><tr><td>Day 3</td><td>用 tiny batch 集成，检查字段、shape、有限值与指标</td><td>正确性证据</td></tr><tr><td>Day 4</td><td><a href="/losh_has_blog/verl-learning/customization/optimization-playbook">优化方法论</a> + <a href="/losh_has_blog/verl-learning/practice/profiling">性能采集</a></td><td>固定 workload 的基线 profile</td></tr><tr><td>Day 5</td><td>做一项 A/B 改动；失败也要写结论</td><td>改动、数据、结论与回退方案</td></tr></tbody></table><p><strong>通关条件：</strong> 你的改动同时具备：明确扩展边界、自动测试、最小集成实验、算法不变量、基准数据和回退开关。</p><h2 id="时间不够时的两条压缩路线" tabindex="-1">时间不够时的两条压缩路线 <a class="header-anchor" href="#时间不够时的两条压缩路线" aria-label="Permalink to &quot;时间不够时的两条压缩路线&quot;">​</a></h2><h3 id="每周只有-3-小时" tabindex="-1">每周只有 3 小时 <a class="header-anchor" href="#每周只有-3-小时" aria-label="Permalink to &quot;每周只有 3 小时&quot;">​</a></h3><p>用 8 周完成，每周只做“核心阅读 60 分钟 + 手算/源码 60 分钟 + 产出物 60 分钟”。删掉拓展论文，不删通关检查。</p><h3 id="已会-rl-只想读-verl-源码" tabindex="-1">已会 RL，只想读 veRL 源码 <a class="header-anchor" href="#已会-rl-只想读-verl-源码" aria-label="Permalink to &quot;已会 RL，只想读 veRL 源码&quot;">​</a></h3><p>先完成入场诊断中的前五题；若能准确回答，按“第 3 周 → 第 4 周 → 第 5 周 → 第 6 周”走。第 2 周只用来核对当前配置实际选择的 estimator 与 loss。</p><h2 id="每周五分钟复盘模板" tabindex="-1">每周五分钟复盘模板 <a class="header-anchor" href="#每周五分钟复盘模板" aria-label="Permalink to &quot;每周五分钟复盘模板&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本周我能预测的新事情：</span></span>
<span class="line"><span>本周被源码推翻的一条理解：</span></span>
<span class="line"><span>我仍无法解释的一个字段：</span></span>
<span class="line"><span>下周最小可验证动作：</span></span>
<span class="line"><span>我将删除或推迟的旁支：</span></span></code></pre></div><p>学习计划不是承诺读完所有页面，而是承诺每周产生一个可检验结果。下一步如果仍不确定术语，先读<a href="./common-questions">小白常见问题</a>；否则直接开始<a href="/losh_has_blog/verl-learning/fundamentals/llm">LLM 如何成为策略</a>。</p>`,41)])])}const b=a(l,[["render",o]]);export{c as __pageData,b as default};
